import React, { useState } from 'react';
import axios from 'axios';

const EnrollUser = () => {
  const [name, setName] = useState('');
  const [id, setId] = useState('');
  const [message, setMessage] = useState('');

  const enrollUser = async () => {
    try {
      // Step 1: Enroll the user
      const enrollResponse = await axios.post('http://localhost:3001/enroll', { id, name });
      setMessage(enrollResponse.data.message);

      if (enrollResponse.status === 200) {
        // Step 2: Get the fingerprint template
        const templateResponse = await axios.post('http://localhost:3001/getTemplate', { id });
        setMessage(templateResponse.data.message);
      }
    } catch (error) {
      setMessage('Error: ' + error.response.data.message);
    }
  };

  return (
    <div>
      <h2>Enroll New User</h2>
      <form onSubmit={(e) => { e.preventDefault(); enrollUser(); }}>
        <div>
          <label>
            Name:
            <input type="text" value={name} onChange={(e) => setName(e.target.value)} required />
          </label>
        </div>
        <div>
          <label>
            ID:
            <input type="text" value={id} onChange={(e) => setId(e.target.value)} required />
          </label>
        </div>
        <button type="submit">Enroll</button>
      </form>
      {message && <p>{message}</p>}
    </div>
  );
};

export default EnrollUser;
